+---
+// Cloudflare-style dotted orange globe.
+// Slow auto-rotation, no interaction.
+// cobe v2: pass CSS pixel dimensions only at init/resize.
+---
+
+<canvas id="globe" class="globe-canvas"></canvas>
+
+<style>
+  .globe-canvas {
+    position: absolute;
+    top: 50%;
+    left: 50%;
+    transform: translate(-50%, -50%);
+    width: min(100vmin, 900px);
+    height: min(100vmin, 900px);
+    pointer-events: none;
+    opacity: 0.32;
+  }
+</style>
+
+<script>
+  import createGlobe from "cobe";
+
+  const canvas = document.getElementById("globe") as HTMLCanvasElement | null;
+  if (canvas && typeof window !== "undefined") {
+    const dpr = Math.min(window.devicePixelRatio || 1, 2);
+
+    let cssW = 0;
+    let cssH = 0;
+    const measure = () => {
+      const rect = canvas.getBoundingClientRect();
+      cssW = Math.max(1, Math.floor(rect.width));
+      cssH = Math.max(1, Math.floor(rect.height));
+    };
+    measure();
+
+    // ~7 minutes per full revolution at 60fps
+    const ROTATION_SPEED = 0.00025;
+    // How much each wheel deltaY pixel kicks the velocity
+    const SCROLL_BOOST = 0.00006;
+    // Per-frame return to base speed (higher = snappier settle)
+    const VELOCITY_DECAY = 0.05;
+    // Clamp so a fast scroll doesn't spin the globe absurdly fast
+    const MAX_VELOCITY = 0.05;
+
+    let phi = 0;
+    let velocity = ROTATION_SPEED;
+
+    window.addEventListener(
+      "wheel",
+      (e) => {
+        velocity += e.deltaY * SCROLL_BOOST;
+        if (velocity > MAX_VELOCITY) velocity = MAX_VELOCITY;
+        if (velocity < -MAX_VELOCITY) velocity = -MAX_VELOCITY;
+      },
+      { passive: true },
+    );
+
+    const globe = createGlobe(canvas, {
+      devicePixelRatio: dpr,
+      width: cssW,
+      height: cssH,
+      phi: 0,
+      theta: 0.25,
+      dark: 1,
+      diffuse: 1.2,
+      mapSamples: 16000,
+      mapBrightness: 5,
+      // Cloudflare orange #F38020
+      baseColor: [0.95, 0.5, 0.13],
+      markerColor: [1, 0.85, 0.4],
+      glowColor: [0.95, 0.5, 0.13],
+      markers: [],
+    });
+
+    // Cobe inserts a `<div style="position:relative;width:100%;height:100%">`
+    // wrapping the canvas. That wrapper sits in normal flow and pushes
+    // the rest of the page below the viewport. Pin it to the viewport so
+    // the canvas centers and the page text stays where it belongs.
+    const wrapper = canvas.parentElement;
+    if (wrapper && wrapper !== document.body) {
+      Object.assign(wrapper.style, {
+        position: "fixed",
+        inset: "0",
+        width: "100%",
+        height: "100%",
+        pointerEvents: "none",
+        zIndex: "0",
+      });
+    }
+
+    window.addEventListener("resize", () => {
+      measure();
+      globe.update({ width: cssW, height: cssH });
+    });
+
+    let rafId = 0;
+    let stopped = false;
+    const tick = () => {
+      if (stopped) return;
+      velocity += (ROTATION_SPEED - velocity) * VELOCITY_DECAY;
+      phi += velocity;
+      globe.update({ phi });
+      rafId = requestAnimationFrame(tick);
+    };
+    rafId = requestAnimationFrame(tick);
+
+    if (import.meta.hot) {
+      import.meta.hot.dispose(() => {
+        stopped = true;
+        cancelAnimationFrame(rafId);
+        globe.destroy();
+      });
+    }
+  }
+</script>

